    rgb.r = texture2D(uCurveLUT, vec2(rgb.r, 0.5)).r;
    rgb.g = texture2D(uCurveLUT, vec2(rgb.g, 0.5)).g;
    rgb.b = texture2D(uCurveLUT, vec2(rgb.b, 0.5)).b;
